package com.school.sis.grade.service;
import com.school.sis.auth.entity.User; import com.school.sis.auth.repository.UserRepository; import com.school.sis.auth.security.SisUserDetails; import com.school.sis.audit.service.AuditService; import com.school.sis.common.exception.*; import com.school.sis.common.response.PageResponse; import com.school.sis.enrollment.entity.EnrollmentSubject; import com.school.sis.enrollment.repository.EnrollmentSubjectRepository; import com.school.sis.grade.dto.*; import com.school.sis.grade.entity.*; import com.school.sis.grade.repository.*; import com.school.sis.schedule.entity.*; import com.school.sis.schedule.repository.ClassScheduleRepository; import com.school.sis.setup.entity.ActiveStatus; import org.springframework.data.domain.Pageable; import org.springframework.security.core.GrantedAuthority; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import java.math.*; import java.time.Instant; import java.util.*; import java.util.function.Function; import java.util.stream.Collectors;
@Service public class GradebookService {
 private static final Set<GradeStatus> EDITABLE=Set.of(GradeStatus.DRAFT,GradeStatus.RETURNED_FOR_CORRECTION); private static final Set<GradeRemark> OVERRIDES=Set.of(GradeRemark.INCOMPLETE,GradeRemark.DROPPED,GradeRemark.WITHDRAWN,GradeRemark.CONDITIONAL);
 private final ClassGradebookRepository gradebooks; private final ClassGradebookCategoryRepository categories; private final GradeAssessmentItemRepository items; private final GradeScoreRepository scores; private final GradeResultOverrideRepository overrides; private final GradebookStatusHistoryRepository history; private final GradingTemplateRepository templates; private final ClassScheduleRepository schedules; private final EnrollmentSubjectRepository subjects; private final UserRepository users; private final GradeService gradeService; private final GradeRepository grades; private final AuditService audit;
 public GradebookService(ClassGradebookRepository g,ClassGradebookCategoryRepository c,GradeAssessmentItemRepository i,GradeScoreRepository s,GradeResultOverrideRepository o,GradebookStatusHistoryRepository h,GradingTemplateRepository t,ClassScheduleRepository cs,EnrollmentSubjectRepository es,UserRepository u,GradeService gs,GradeRepository gr,AuditService a){gradebooks=g;categories=c;items=i;scores=s;overrides=o;history=h;templates=t;schedules=cs;subjects=es;users=u;gradeService=gs;grades=gr;audit=a;}
 @Transactional(readOnly=true) public PageResponse<GradeClassSummaryResponse> classes(String scope,UUID schoolYearId,UUID semesterId,GradeStatus status,String search,Pageable page,SisUserDetails principal){List<ClassSchedule> all=schedules.findAll().stream().filter(s->s.getStatus()==ScheduleStatus.ACTIVE).filter(s->schoolYearId==null||s.getSchoolYear().getId().equals(schoolYearId)).filter(s->semesterId==null||s.getSemester().getId().equals(semesterId)).filter(s->search==null||search.isBlank()||(s.getCourse().getCourseCode()+" "+s.getCourse().getCourseTitle()+" "+s.getSection().getSectionCode()).toLowerCase().contains(search.toLowerCase())).filter(s->allowedScope(scope,s,principal)).filter(s->{var g=gradebooks.findByScheduleId(s.getId()).orElse(null);return status==null||(g!=null&&g.getStatus()==status);}).toList();int from=Math.min(page.getPageNumber()*page.getPageSize(),all.size()),to=Math.min(from+page.getPageSize(),all.size());List<GradeClassSummaryResponse> content=all.subList(from,to).stream().map(this::summary).toList();return new PageResponse<>(content,page.getPageNumber(),page.getPageSize(),all.size(),(int)Math.ceil(all.size()/(double)page.getPageSize()));}
 @Transactional public GradebookResponse get(UUID scheduleId,SisUserDetails principal){ClassSchedule schedule=findSchedule(scheduleId);ensureView(schedule,principal);ClassGradebook g=gradebooks.findByScheduleId(scheduleId).orElseThrow(()->new NotFoundException("Gradebook is not initialized"));syncRoster(g);return response(g);}
 @Transactional public GradebookResponse initialize(UUID scheduleId,UUID templateId,SisUserDetails principal){ClassSchedule schedule=findSchedule(scheduleId);ensureFaculty(schedule,principal);if(gradebooks.findByScheduleId(scheduleId).isPresent())throw new BusinessRuleException("Gradebook is already initialized");GradingTemplate t=templates.findById(templateId).orElseThrow(()->new NotFoundException("Grading template not found"));if(t.getStatus()!=ActiveStatus.ACTIVE||!t.getProgram().getId().equals(schedule.getSection().getProgram().getId())||!t.getCourse().getId().equals(schedule.getCourse().getId()))throw new BusinessRuleException("Template does not match this class program and course");ClassGradebook g=new ClassGradebook();g.setSchedule(schedule);g.setTemplate(t);g.setScale(t.getScale());g.setMidtermWeight(t.getMidtermWeight());g.setFinalWeight(t.getFinalWeight());g.setInitializedBy(user(principal));for(var tc:t.getCategories()){ClassGradebookCategory c=new ClassGradebookCategory();c.setTemplateCategory(tc);c.setPeriod(tc.getPeriod());c.setCategoryName(tc.getCategoryName());c.setWeight(tc.getWeight());c.setSortOrder(tc.getSortOrder());g.addCategory(c);}g=gradebooks.save(g);record(g,null,GradeStatus.DRAFT,"Gradebook initialized",user(principal));return response(g);}
 @Transactional public GradebookResponse saveItem(UUID scheduleId,GradebookRequests.Item r,SisUserDetails principal){ClassGradebook g=editable(scheduleId,principal);ClassGradebookCategory c=categories.findById(r.categoryId()).filter(x->x.getGradebook().getId().equals(g.getId())).orElseThrow(()->new BusinessRuleException("Category does not belong to this gradebook"));GradeAssessmentItem item=r.id()==null?new GradeAssessmentItem():items.findById(r.id()).orElseThrow(()->new NotFoundException("Assessment item not found"));item.setGradebook(g);item.setCategory(c);item.setTitle(r.title().trim());item.setMaximumScore(r.maximumScore());item.setDueDate(r.dueDate());item.setSortOrder(r.sortOrder());item.setArchived(false);item=items.save(item);syncItemScores(item);return response(g);}
 @Transactional public GradebookResponse archiveItem(UUID scheduleId,UUID itemId,SisUserDetails principal){ClassGradebook g=editable(scheduleId,principal);GradeAssessmentItem i=items.findById(itemId).filter(x->x.getGradebook().getId().equals(g.getId())).orElseThrow(()->new NotFoundException("Assessment item not found"));i.setArchived(true);return response(g);}
 @Transactional public GradebookResponse saveScores(UUID scheduleId,GradebookRequests.Scores r,SisUserDetails principal){ClassGradebook g=editable(scheduleId,principal);Map<UUID,GradeAssessmentItem> itemMap=items.findByGradebookIdAndArchivedFalseOrderBySortOrderAsc(g.getId()).stream().collect(Collectors.toMap(GradeAssessmentItem::getId,Function.identity()));Set<UUID> roster=subjects.findConfirmedEnrolledSubjectsByScheduleId(scheduleId).stream().map(EnrollmentSubject::getId).collect(Collectors.toSet());for(var entry:r.scores()){GradeAssessmentItem item=itemMap.get(entry.itemId());if(item==null||!roster.contains(entry.enrollmentSubjectId()))throw new BusinessRuleException("Score does not belong to this class");GradeScore score=scores.findByItemIdAndEnrollmentSubjectId(entry.itemId(),entry.enrollmentSubjectId()).orElseGet(GradeScore::new);score.setItem(item);score.setEnrollmentSubject(subjects.findById(entry.enrollmentSubjectId()).orElseThrow(()->new NotFoundException("Enrollment subject not found")));validateScore(item,entry);score.setStatus(entry.status());score.setScore(entry.status()==ScoreStatus.SCORED?entry.score():entry.status()==ScoreStatus.ABSENT?BigDecimal.ZERO:null);scores.save(score);}return response(g);}
 @Transactional public GradebookResponse saveOverride(UUID scheduleId,GradebookRequests.Override r,SisUserDetails principal){ClassGradebook g=editable(scheduleId,principal);if(!OVERRIDES.contains(r.remark()))throw new BusinessRuleException("Invalid non-numeric override");EnrollmentSubject subject=subjects.findById(r.enrollmentSubjectId()).filter(s->s.getClassSchedule().getId().equals(scheduleId)).orElseThrow(()->new BusinessRuleException("Student does not belong to this class"));GradeResultOverride o=overrides.findByGradebookIdAndEnrollmentSubjectId(g.getId(),r.enrollmentSubjectId()).orElseGet(GradeResultOverride::new);o.setGradebook(g);o.setEnrollmentSubject(subject);o.setRemark(r.remark());o.setReason(r.reason().trim());overrides.save(o);return response(g);}
 @Transactional public GradebookResponse removeOverride(UUID scheduleId,UUID subjectId,SisUserDetails principal){ClassGradebook g=editable(scheduleId,principal);overrides.findByGradebookIdAndEnrollmentSubjectId(g.getId(),subjectId).ifPresent(overrides::delete);return response(g);}
 @Transactional public GradebookResponse submit(UUID scheduleId,SisUserDetails principal){ClassGradebook g=editable(scheduleId,principal);GradebookResponse view=response(g);if(!view.validationIssues().isEmpty())throw new BusinessRuleException(String.join("; ",view.validationIssues()));List<GradeEntryRequest> entries=view.students().stream().map(s->new GradeEntryRequest(s.enrollmentSubjectId(),s.gradePoint(),s.remark())).toList();gradeService.encode(scheduleId,new GradeEncodeRequest(entries),principal);List<Grade> official=grades.findByEnrollmentSubjectIdIn(entries.stream().map(GradeEntryRequest::enrollmentSubjectId).toList());Map<UUID,GradebookResponse.StudentResult> resultMap=view.students().stream().collect(Collectors.toMap(GradebookResponse.StudentResult::enrollmentSubjectId,Function.identity()));official.forEach(x->{var result=resultMap.get(x.getEnrollmentSubject().getId());x.setMidtermPercentage(result.midtermPercentage());x.setFinalPeriodPercentage(result.finalPeriodPercentage());x.setFinalPercentage(result.finalPercentage());});gradeService.submit(scheduleId,principal);transition(g,GradeStatus.SUBMITTED,"Gradebook submitted",user(principal));g.setSubmittedBy(user(principal));g.setSubmittedAt(Instant.now());return response(g);}
 @Transactional public GradebookResponse returnForCorrection(UUID scheduleId,String reason,SisUserDetails principal){ClassGradebook g=findGradebook(scheduleId);ensureReviewer(g.getSchedule(),principal);if(g.getStatus()!=GradeStatus.SUBMITTED)throw new BusinessRuleException("Only submitted gradebooks can be returned");gradeService.returnForCorrection(scheduleId,reason,principal);transition(g,GradeStatus.RETURNED_FOR_CORRECTION,reason,user(principal));g.setLatestCorrectionReason(reason);return response(g);}
 @Transactional public GradebookResponse approve(UUID scheduleId,SisUserDetails principal){ClassGradebook g=findGradebook(scheduleId);ensureReviewer(g.getSchedule(),principal);if(g.getStatus()!=GradeStatus.SUBMITTED)throw new BusinessRuleException("Only submitted gradebooks can be approved");gradeService.approve(scheduleId,principal);transition(g,GradeStatus.APPROVED,"Gradebook approved",user(principal));g.setApprovedBy(user(principal));g.setApprovedAt(Instant.now());return response(g);}
 @Transactional public GradebookResponse lock(UUID scheduleId,SisUserDetails principal){ClassGradebook g=findGradebook(scheduleId);ensureLocker(principal);if(g.getStatus()!=GradeStatus.APPROVED)throw new BusinessRuleException("Only approved gradebooks can be locked");gradeService.lock(scheduleId,principal);transition(g,GradeStatus.LOCKED,"Gradebook locked",user(principal));g.setLockedBy(user(principal));g.setLockedAt(Instant.now());return response(g);}
 private void validateScore(GradeAssessmentItem item,GradebookRequests.Score r){if(r.status()==ScoreStatus.SCORED&&(r.score()==null||r.score().signum()<0||r.score().compareTo(item.getMaximumScore())>0))throw new BusinessRuleException("Score must be between zero and the assessment maximum");}
 private ClassGradebook editable(UUID scheduleId,SisUserDetails p){ClassGradebook g=findGradebook(scheduleId);ensureFaculty(g.getSchedule(),p);if(!EDITABLE.contains(g.getStatus()))throw new BusinessRuleException("Submitted, approved, or locked gradebooks cannot be edited");syncRoster(g);return g;}
 private void syncRoster(ClassGradebook g){if(!EDITABLE.contains(g.getStatus()))return;items.findByGradebookIdAndArchivedFalseOrderBySortOrderAsc(g.getId()).forEach(this::syncItemScores);} private void syncItemScores(GradeAssessmentItem item){for(var subject:subjects.findConfirmedEnrolledSubjectsByScheduleId(item.getGradebook().getSchedule().getId()))if(scores.findByItemIdAndEnrollmentSubjectId(item.getId(),subject.getId()).isEmpty()){GradeScore s=new GradeScore();s.setItem(item);s.setEnrollmentSubject(subject);scores.save(s);}}
 private GradebookResponse response(ClassGradebook g){var cats=categories.findByGradebookIdOrderByPeriodAscSortOrderAsc(g.getId());var activeItems=items.findByGradebookIdAndArchivedFalseOrderBySortOrderAsc(g.getId());var scoreList=scores.findByItemGradebookId(g.getId());var overrideMap=overrides.findByGradebookId(g.getId()).stream().collect(Collectors.toMap(x->x.getEnrollmentSubject().getId(),Function.identity()));var roster=subjects.findConfirmedEnrolledSubjectsByScheduleId(g.getSchedule().getId());var scoreMap=scoreList.stream().collect(Collectors.groupingBy(x->x.getEnrollmentSubject().getId()));List<GradebookResponse.StudentResult> results=roster.stream().map(s->calculate(g,s,cats,activeItems,scoreMap.getOrDefault(s.getId(),List.of()),overrideMap.get(s.getId()))).toList();List<String> issues=new ArrayList<>();for(var c:cats)if(activeItems.stream().noneMatch(i->i.getCategory().getId().equals(c.getId())))issues.add(c.getPeriod()+" / "+c.getCategoryName()+" has no assessment items");long pending=results.stream().filter(r->!r.complete()).count();if(pending>0)issues.add(pending+" student result(s) still have pending scores");return new GradebookResponse(g.getId(),g.getSchedule().getId(),g.getSchedule().getCourse().getCourseCode(),g.getSchedule().getCourse().getCourseTitle(),g.getSchedule().getSection().getSectionCode(),facultyName(g.getSchedule()),g.getSchedule().getSchoolYear().getSchoolYear(),g.getSchedule().getSemester().getName(),g.getStatus(),g.getLatestCorrectionReason(),g.getMidtermWeight(),g.getFinalWeight(),cats.stream().map(c->new GradebookResponse.Category(c.getId(),c.getPeriod(),c.getCategoryName(),c.getWeight(),c.getSortOrder())).toList(),activeItems.stream().map(i->new GradebookResponse.Item(i.getId(),i.getCategory().getId(),i.getCategory().getPeriod(),i.getCategory().getCategoryName(),i.getTitle(),i.getMaximumScore(),i.getDueDate(),i.getSortOrder())).toList(),results,history.findByGradebookIdOrderByChangedAtDesc(g.getId()).stream().map(h->new GradebookResponse.History(h.getFromStatus(),h.getToStatus(),h.getReason(),h.getChangedBy()==null?null:h.getChangedBy().getFullName(),h.getChangedAt())).toList(),issues);}
 private GradebookResponse.StudentResult calculate(ClassGradebook g,EnrollmentSubject subject,List<ClassGradebookCategory> cats,List<GradeAssessmentItem> itemList,List<GradeScore> studentScores,GradeResultOverride override){Map<UUID,GradeScore> byItem=studentScores.stream().collect(Collectors.toMap(x->x.getItem().getId(),Function.identity()));boolean complete=true;Map<GradingPeriod,BigDecimal> periods=new EnumMap<>(GradingPeriod.class);for(var period:GradingPeriod.values()){BigDecimal weighted=BigDecimal.ZERO;for(var cat:cats.stream().filter(c->c.getPeriod()==period).toList()){BigDecimal earned=BigDecimal.ZERO,possible=BigDecimal.ZERO;for(var item:itemList.stream().filter(i->i.getCategory().getId().equals(cat.getId())).toList()){GradeScore score=byItem.get(item.getId());if(score==null||score.getStatus()==ScoreStatus.PENDING){complete=false;continue;}if(score.getStatus()==ScoreStatus.EXCUSED)continue;possible=possible.add(item.getMaximumScore());earned=earned.add(score.getStatus()==ScoreStatus.SCORED?score.getScore():BigDecimal.ZERO);}BigDecimal pct=possible.signum()==0?BigDecimal.ZERO:earned.multiply(new BigDecimal("100")).divide(possible,4,RoundingMode.HALF_UP);weighted=weighted.add(pct.multiply(cat.getWeight()).divide(new BigDecimal("100"),4,RoundingMode.HALF_UP));}periods.put(period,weighted.setScale(2,RoundingMode.HALF_UP));}BigDecimal mid=periods.getOrDefault(GradingPeriod.MIDTERM,BigDecimal.ZERO),fin=periods.getOrDefault(GradingPeriod.FINAL,BigDecimal.ZERO),total=mid.multiply(g.getMidtermWeight()).add(fin.multiply(g.getFinalWeight())).divide(new BigDecimal("100"),2,RoundingMode.HALF_UP);GradingScaleBand band=g.getScale().getBands().stream().filter(b->total.compareTo(b.getMinimumPercentage())>=0&&total.compareTo(b.getMaximumPercentage())<=0).findFirst().orElse(null);BigDecimal point=override==null&&band!=null?band.getGradePoint():null;GradeRemark remark=override!=null?override.getRemark():band==null?GradeRemark.NO_GRADE:band.getRemark();List<GradebookResponse.Score> values=itemList.stream().map(i->{GradeScore s=byItem.get(i.getId());return new GradebookResponse.Score(i.getId(),s==null?null:s.getScore(),s==null?ScoreStatus.PENDING:s.getStatus());}).toList();var st=subject.getEnrollment().getStudent();return new GradebookResponse.StudentResult(subject.getId(),st.getId(),st.getStudentNumber(),studentName(st),values,mid,fin,total,point,remark,override==null?null:override.getReason(),complete||override!=null);}
 private GradeClassSummaryResponse summary(ClassSchedule s){var g=gradebooks.findByScheduleId(s.getId()).orElse(null);int count=(int)subjects.countByClassScheduleIdAndStatusAndEnrollmentStatus(s.getId(),com.school.sis.enrollment.entity.EnrollmentSubjectStatus.ENROLLED,com.school.sis.enrollment.entity.EnrollmentStatus.CONFIRMED);int done=g==null?0:(int)response(g).students().stream().filter(GradebookResponse.StudentResult::complete).count();var d=s.getSection().getProgram().getDepartment();return new GradeClassSummaryResponse(s.getId(),s.getCourse().getId(),s.getCourse().getCourseCode(),s.getCourse().getCourseTitle(),s.getSection().getSectionCode(),s.getFaculty().getId(),facultyName(s),s.getSection().getProgram().getId(),s.getSection().getProgram().getProgramCode(),d.getId(),d.getDepartmentCode(),s.getSchoolYear().getId(),s.getSchoolYear().getSchoolYear(),s.getSemester().getId(),s.getSemester().getName(),count,done,g==null?GradeStatus.DRAFT:g.getStatus(),g==null?null:g.getLatestCorrectionReason(),g!=null);}
 private boolean allowedScope(String scope,ClassSchedule s,SisUserDetails p){if("MY".equalsIgnoreCase(scope))return p!=null&&p.facultyId()!=null&&p.facultyId().equals(s.getFaculty().getId());if("REVIEW".equalsIgnoreCase(scope)){if(!has(p,"GRADE_REVIEW"))return false;User u=user(p);return has(p,"ROLE_SUPER_ADMIN")||(u!=null&&u.getFaculty()!=null&&u.getFaculty().getDepartment().getId().equals(s.getSection().getProgram().getDepartment().getId()));}return "LOCK".equalsIgnoreCase(scope)&&has(p,"GRADE_LOCK");}
 private void ensureView(ClassSchedule s,SisUserDetails p){if(allowedScope("MY",s,p)||allowedScope("REVIEW",s,p)||allowedScope("LOCK",s,p)||has(p,"GRADE_APPROVE"))return;throw new BusinessRuleException("User cannot access this gradebook");} private void ensureFaculty(ClassSchedule s,SisUserDetails p){if(has(p,"GRADE_APPROVE")||has(p,"ROLE_SUPER_ADMIN"))return;if(!has(p,"GRADE_ENCODE")||p.facultyId()==null||!p.facultyId().equals(s.getFaculty().getId()))throw new BusinessRuleException("Faculty can only manage assigned classes");} private void ensureReviewer(ClassSchedule s,SisUserDetails p){if(!allowedScope("REVIEW",s,p)&&!has(p,"GRADE_APPROVE"))throw new BusinessRuleException("Reviewer can only approve classes in their department");} private void ensureLocker(SisUserDetails p){if(!has(p,"GRADE_LOCK")&&!has(p,"GRADE_APPROVE"))throw new BusinessRuleException("User is not allowed to lock grades");}
 private void transition(ClassGradebook g,GradeStatus to,String reason,User u){GradeStatus from=g.getStatus();g.setStatus(to);record(g,from,to,reason,u);} private void record(ClassGradebook g,GradeStatus from,GradeStatus to,String reason,User u){GradebookStatusHistory h=new GradebookStatusHistory();h.setGradebook(g);h.setFromStatus(from);h.setToStatus(to);h.setReason(reason);h.setChangedBy(u);history.save(h);audit.log(u,"GRADEBOOK_"+to,"GRADE","ClassGradebook",g.getId(),from==null?null:Map.of("status",from),Map.of("status",to,"reason",reason));}
 private ClassSchedule findSchedule(UUID id){return schedules.findById(id).orElseThrow(()->new NotFoundException("Schedule not found"));} private ClassGradebook findGradebook(UUID id){return gradebooks.findByScheduleId(id).orElseThrow(()->new NotFoundException("Gradebook is not initialized"));} private User user(SisUserDetails p){return p==null?null:users.findById(p.id()).orElse(null);} private boolean has(SisUserDetails p,String a){return p!=null&&p.getAuthorities().stream().map(GrantedAuthority::getAuthority).anyMatch(a::equals);} private String facultyName(ClassSchedule s){return s.getFaculty().getFirstName()+" "+s.getFaculty().getLastName();} private String studentName(com.school.sis.student.entity.Student s){return (s.getFirstName()+" "+(s.getMiddleName()==null?"":s.getMiddleName()+" ")+s.getLastName()).replaceAll("\\s+"," ").trim();}
}
